package com.example.demo.controller;
import com.example.demo.dto.*; import com.example.demo.service.SalesService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/cart") public class CartController {private final SalesService service;public CartController(SalesService service){this.service=service;}@GetMapping public List<CartItemResponse> list(@RequestHeader("Authorization")String auth){return service.cart(auth);}@PostMapping("/items") public List<CartItemResponse> add(@RequestHeader("Authorization")String auth,@RequestBody CartRequest r){return service.addCart(auth,r);}@PutMapping("/items/{productId}") public List<CartItemResponse> update(@RequestHeader("Authorization")String auth,@PathVariable long productId,@RequestBody CartRequest r){return service.updateCart(auth,productId,r);}@DeleteMapping("/items/{productId}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@RequestHeader("Authorization")String auth,@PathVariable long productId){service.removeCart(auth,productId);}}
